            char smallest = s[0];
            for (char c : s) {
                if (c < smallest) {
                    smallest = c;
                }
            }
            s.erase(s.find(smallest));
            result += smallest;

            char largest = s[0];
            for (char c : s) {
                if (c > largest) {
                    largest = c;
